CREATE TABLE IF NOT EXISTS service_marketplace_items(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),code text NOT NULL UNIQUE,name text NOT NULL,item_type text NOT NULL CHECK(item_type IN('service_pack','connector','theme','extension')),category text NOT NULL,description text NOT NULL DEFAULT '',provider text NOT NULL DEFAULT 'ServicePro',industries jsonb NOT NULL DEFAULT '["all"]'::jsonb,features jsonb NOT NULL DEFAULT '[]'::jsonb,accent_color text NOT NULL DEFAULT '#1c7c68',status text NOT NULL DEFAULT 'published',created_at timestamptz NOT NULL DEFAULT now(),updated_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS service_marketplace_installations(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),tenant_id text NOT NULL,item_id uuid NOT NULL REFERENCES service_marketplace_items(id) ON DELETE CASCADE,status text NOT NULL DEFAULT 'active',configuration jsonb NOT NULL DEFAULT '{}'::jsonb,installed_by text NOT NULL DEFAULT '',installed_at timestamptz NOT NULL DEFAULT now(),updated_at timestamptz NOT NULL DEFAULT now(),UNIQUE(tenant_id,item_id));
CREATE INDEX IF NOT EXISTS idx_service_marketplace_installations_tenant ON service_marketplace_installations(tenant_id,status,installed_at DESC);
